INSERT INTO audit_logs (id, user_id, table_name, record_id, action, old_data, new_data, created_at) VALUES ('2aa6c217-7251-4212-886d-f965265bec34', NULL, 'products', 'd856fa79-32fd-472d-a10a-5ed0d17c8b43', 'UPDATE', '{"id": "d856fa79-32fd-472d-a10a-5ed0d17c8b43", "sku": "DR410.0025", "price": 1.13, "title_en": null, "title_it": "New Cristal", "is_active": true, "attributes": {"ml": 0, "colore": "Bianco", "finitura": "Nessuna finitura", "categoria": "Dispenser", "materiale": "PP", "imboccatura": "GCMI 24/410"}, "created_at": "2026-06-16T09:25:52.091032+00:00", "image_urls": ["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/DR410.0025.jpg"], "category_id": null, "price_tiers": [], "box_quantity": 700, "is_accessory": false, "description_en": "<pre data-placeholder=\"Traduzione\" dir=\"ltr\" id=\"tw-target-text\"> The New Cristal dispenser has been specially designed to be coordinated with the New Cristal bottle, adapting the lines and the design of the bottle itself, in order to give it the maximum aesthetic balance. Ideal for dispensing a wide range of cosmetic products, for cleansing and hair care.</pre>", "description_it": "<p>Il dispenser New Cristal &egrave; stato appositamente progettato per essere coordinato al flacone New Cristal, adattandolo le linee e il desing del flacone stesso, al fine di conferirgli il massimo equilibrio estetico. Ideale per l&rsquo;erogazione di un&rsquo;ampia gamma di prodotti cosmetici, per la detergenza e per la cura dei capelli.</p>", "stock_quantity": 0}', '{"id": "d856fa79-32fd-472d-a10a-5ed0d17c8b43", "sku": "DR410.0025", "price": 1.13, "title_en": null, "title_it": "New Cristal", "is_active": true, "attributes": {"ml": 0, "colore": "Bianco", "finitura": "Nessuna finitura", "categoria": "Dispenser", "materiale": "PP", "imboccatura": "GCMI 24/410"}, "created_at": "2026-06-16T09:25:52.091032+00:00", "image_urls": ["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/DR410.0025.jpg"], "category_id": null, "price_tiers": [], "box_quantity": 700, "is_accessory": true, "description_en": "<pre data-placeholder=\"Traduzione\" dir=\"ltr\" id=\"tw-target-text\"> The New Cristal dispenser has been specially designed to be coordinated with the New Cristal bottle, adapting the lines and the design of the bottle itself, in order to give it the maximum aesthetic balance. Ideal for dispensing a wide range of cosmetic products, for cleansing and hair care.</pre>", "description_it": "<p>Il dispenser New Cristal &egrave; stato appositamente progettato per essere coordinato al flacone New Cristal, adattandolo le linee e il desing del flacone stesso, al fine di conferirgli il massimo equilibrio estetico. Ideale per l&rsquo;erogazione di un&rsquo;ampia gamma di prodotti cosmetici, per la detergenza e per la cura dei capelli.</p>", "stock_quantity": 0}', '2026-06-18T10:58:48.157221+00:00');
